const fs = require('fs');
const path = require('path');
const nock = require('nock');

nock('http://someurl.com')
  .get(/success/)
  .times(100)
  .replyWithFile(200, path.join(__dirname, 'fixtures/android.jpg'), {
    'Content-Type': 'image/jpeg',
  });

