  });

nock('https://someurl.com')
  .get(/timeout/)
  .delayConnection(5000)
  .times(100)
  .replyWithFile(200, path.join(__dirname, 'fixtures/android.jpg'), {
    'Content-Type': 'image/jpeg',
  });

nock('http://someurl.com')
  .get(/error/)
  .times(100)
  .reply(404, 'Not Found');

nock('http://cdn.shopify.com')
